from collections import defaultdict, deque, Counter

cells = [(5,7),(5,8),(5,9),(6,5),(6,8),(7,7),(7,9)]
dirs=[(1,0),(-1,0),(0,1),(0,-1)]
comp={}
def find(u):
    while comp[u]!=u:
        comp[u]=comp[comp[u]]
        u=comp[u]
    return u
for c in cells:
    comp[c]=c
for a in cells:
    for d in dirs:
        b=(a[0]+d[0],a[1]+d[1])
        if b in comp:
            # union
            ra=find(a); rb=find(b)
            if ra!=rb:
                comp[rb]=ra
# compute groups
groups=defaultdict(list)
for a in cells:
    groups[find(a)].append(a)
groups

proto=[(5,7),(5,8),(5,9),(6,8)]
singles=[(6,5),(7,7),(7,9)]
import math, itertools
def dist(single):
    return min(abs(single[0]-p[0])+abs(single[1]-p[1]) for p in proto)
for s in singles:
    print(s, dist(s))

def clusters(cells, diag=False):
    dirs=[(1,0),(-1,0),(0,1),(0,-1)]
    if diag:
        dirs += [(1,1),(1,-1),(-1,1),(-1,-1)]
    comp={}
    for c in cells:
        comp[c]=c
    def find(u):
        while comp[u]!=u:
            comp[u]=comp[comp[u]]
            u=comp[u]
        return u
    for a in cells:
        for d in dirs:
            b=(a[0]+d[0],a[1]+d[1])
            if b in comp:
                ra=find(a); rb=find(b)
                if ra!=rb:
                    comp[rb]=ra
    groups=defaultdict(list)
    for a in cells:
        groups[find(a)].append(a)
    return list(groups.values())
print(clusters(cells,diag=True))

